{
  "record_plan_selection": {
    "type": "function",
    "function": {
      "name": "record_plan_selection",
      "description": "Record parent's chosen savings plan and preferences.",
      "parameters": {
        "type": "object",
        "properties": {
          "user_id": {
            "type": "string",
            "description": "Unique user identifier."
          },
          "selected_plan": {
            "type": "string",
            "enum": [
              "installment_savings",
              "education_fund"
            ],
            "description": "Chosen savings plan."
          },
          "monthly_deposit": {
            "type": "number",
            "description": "Monthly deposit amount (for installment savings). Must be a positive number."
          },
          "lump_sum_deposit": {
            "type": "number",
            "description": "Lump sum deposit amount (for education fund). Must be a positive number."
          },
          "interest_rate_boost_eligible": {
            "type": "boolean",
            "description": "Whether parent is interested in offline workshop for rate boost."
          },
          "contact_preference": {
            "type": "string",
            "enum": [
              "call",
              "wechat",
              "app"
            ],
            "description": "Preferred contact method for follow-up."
          }
        },
        "required": [
          "user_id",
          "selected_plan",
          "contact_preference"
        ]
      }
    }
  }
}

{
  "get_family_profile": {
    "type": "function",
    "function": {
      "name": "get_family_profile",
      "description": "Records the customer's family size and household income level to tailor the explanation of the account's benefits.",
      "parameters": {
        "type": "object",
        "properties": {
          "family_size": {
            "type": "string",
            "description": "The number of people in the customer's household (e.g., 2, 4)."
          },
          "income_level_bracket": {
            "type": "string",
            "description": "The customer's approximate monthly household income bracket (e.g., 5k-10k, 10k-15k)."
          }
        },
        "required": [
          "family_size",
          "income_level_bracket"
        ]
      }
    }
  }
}

{
  "collect_information": {
    "type": "function",
    "function": {
      "name": "collect_information",
      "description": "Collect and record the customer's basic personal and financial information for credit card application.",
      "parameters": {
        "type": "object",
        "properties": {
          "age": {
            "type": "string",
            "description": "The age provided by the customer."
          },
          "occupation": {
            "type": "string",
            "description": "The occupation provided by the customer."
          },
          "monthly_income_range": {
            "type": "string",
            "description": "The approximate monthly income range provided by the customer. Format: Amount plus currency (e.g. '10000 $')."
          }
        },
        "required": [
          "age",
          "occupation",
          "monthly_income_range"
        ]
      }
    }
  },
  "book_service": {
    "type": "function",
    "function": {
      "name": "book_service",
      "description": "Record the customer's preferred area and time for in-branch credit card application service.",
      "parameters": {
        "type": "object",
        "properties": {
          "preferred_area": {
            "type": "string",
            "description": "The convenient area for in-branch application provided by the customer."
          },
          "preferred_time_frame": {
            "type": "string",
            "description": "The approximate time frame for in-branch application provided by the customer."
          }
        },
        "required": [
          "preferred_area",
          "preferred_time_frame"
        ]
      }
    }
  }
}

{
  "farmer_loan_assessment": {
    "type": "function",
    "function": {
      "name": "farmer_loan_assessment",
      "description": "Collects essential information from the farmer to assess eligibility, determine the appropriate loan product, and initiate the application process.",
      "parameters": {
        "type": "object",
        "properties": {
          "farmer_name": {
            "type": "string",
            "description": "Full name of the farmer."
          },
          "id_number": {
            "type": "string",
            "description": "Farmer's ID card number."
          },
          "village_name": {
            "type": "string",
            "description": "Name of the farmer's village."
          },
          "loan_purpose": {
            "type": "string",
            "description": "Specific use of funds (e.g., 'buy wheat seeds and fertilizer', 'build new chicken coop')."
          },
          "requested_amount": {
            "type": "number",
            "description": "The loan amount the farmer is requesting (in RMB)."
          },
          "loan_name": {
            "type": "string",
            "enum": [
              "planting loan",
              "livestock loan"
            ],
            "description": "Name of funds (choose between planting loan or livestock loan)."
          }
        },
        "required": [
          "farmer_name",
          "id_number",
          "village_name",
          "loan_purpose",
          "requested_amount",
          "loan_name"
        ]
      }
    }
  },
  "farming_status": {
    "type": "function",
    "function": {
      "name": "farming_status",
      "description": "Records the customer's farming status and loan purpose after verification.",
      "parameters": {
        "type": "object",
        "properties": {
          "contract_certificate": {
            "type": "string",
            "enum": [
              "yes",
              "no"
            ],
            "description": "Record whether the customer has the contract certification."
          },
          "farming_filing_proof": {
            "type": "string",
            "enum": [
              "yes",
              "no"
            ],
            "description": "Record whether the customer has applied for the farming filing proof."
          },
          "primary_purpose": {
            "type": "string",
            "description": "The purpose of applying the funds (why they need to apply for the fund)."
          }
        },
        "required": [
          "contract_certificate",
          "farming_filing_proof",
          "primary_purpose"
        ]
      }
    }
  }
}

{
