{
  "query_customer_account": {
    "type": "function",
    "function": {
      "name": "query_customer_account",
      "description": "Queries the customer's account information from the system using provided details.",
      "parameters": {
        "type": "object",
        "properties": {
          "client_name": {
            "type": "string",
            "description": "Client's full name. Should only include English letters."
          },
          "mobile_number": {
            "type": "string",
            "description": "User's mobile phone number. Should be 11 digits."
          }
        },
        "required": [
          "client_name",
          "mobile_number"
        ]
      }
    }
  },
  "record_loyalty_info": {
    "type": "function",
    "function": {
      "name": "record_loyalty_info",
      "description": "Records client contact information for loyalty program enrollment.",
      "parameters": {
        "type": "object",
        "properties": {
          "email": {
            "type": "string",
            "description": "Valid email format (e.g. xx@xx.com)."
          }
        },
        "required": [
          "email"
        ]
      }
    }
  },
  "check_payment": {
    "type": "function",
    "function": {
      "name": "check_payment",
      "description": "Check if the user paid successfully.",
      "parameters": {
        "type": "object",
        "properties": {
          "proof_number": {
            "type": "string",
            "description": "Valid payment proof number in the form of 1234-XX-1111."
          }
        },
        "required": [
          "proof_number"
        ]
      }
    }
  }
}

