        "type": "object",
        "properties": {
          "wellness_type": {
            "type": "string",
            "description": "The type of wellness experience the customer prefers."
          },
          "itinerary_intensity": {
            "type": "string",
            "description": "The desired intensity level of the itinerary."
          },
          "dietary_requirements": {
            "type": "string",
            "description": "Any special dietary needs or restrictions."
